    68→        &mut self,
    69→        nested_body_def_id: LocalDefId,
    70→    ) -> &SmallVec<[FieldIdx; 8]> {
    71→        &self.propagated_borrowck_results[&nested_body_def_id].used_mut_upvars
    72→    }
