   325→            err.note(msg);
   326→            Ok(())
   327→        })
   328→        .unwrap();
   329→
   330→        err
   331→    } else {
   332→        let mut err = infcx.dcx().struct_span_note(def_span, "no external requirements");
   333→        regioncx.annotate(tcx, &mut err);
   334→        err
   335→    };
   336→
   337→    // FIXME(@lcnr): We currently don't dump the inferred hidden types here.
